import React, { useState, useEffect } from "react";
import {
  Container,
  Typography,
  Grid,
  Card,
  CardContent,
  Button,
  Box,
  Chip,
  Divider,
  Avatar,
} from "@mui/material";
import CalendarMonthIcon from "@mui/icons-material/CalendarMonth";
import PersonIcon from "@mui/icons-material/Person";
import LocalHospitalIcon from "@mui/icons-material/LocalHospital";
import { useNavigate } from "react-router-dom";

export default function PatientDashboard() {
  const navigate = useNavigate();
  const [appointments, setAppointments] = useState([]);
  const [userName] = useState("Aashika Shrestha"); // You can make this dynamic later

  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem("appointments") || "[]");
    setAppointments(saved.sort((a, b) => new Date(b.date) - new Date(a.date)));
  }, []);

  return (
    <Container
      maxWidth="lg"
      sx={{ py: 6, bgcolor: "#f8fafd", minHeight: "100vh" }}
    >
      <Box sx={{ mb: 5, textAlign: "center" }}>
        <Avatar
          sx={{
            width: 100,
            height: 100,
            mx: "auto",
            mb: 2,
            bgcolor: "#1976d2",
          }}
        >
          👩‍⚕️
        </Avatar>
        <Typography variant="h4" fontWeight={700} gutterBottom>
          Welcome back, {userName}!
        </Typography>
        <Typography color="text.secondary">
          Manage your health appointments
        </Typography>
      </Box>

      <Grid container spacing={4}>
        {/* Quick Stats */}
        <Grid item xs={12} md={4}>
          <Card sx={{ height: "100%", borderRadius: 4, boxShadow: 3 }}>
            <CardContent sx={{ textAlign: "center", py: 4 }}>
              <Typography variant="h3" fontWeight={700} color="#1976d2">
                {appointments.length}
              </Typography>
              <Typography variant="h6" color="text.secondary">
                Total Appointments
              </Typography>
            </CardContent>
          </Card>
        </Grid>

        {/* Upcoming Appointments */}
        <Grid item xs={12} md={8}>
          <Typography variant="h5" fontWeight={600} gutterBottom>
            Upcoming Appointments
          </Typography>

          {appointments.length === 0 ? (
            <Card sx={{ p: 6, textAlign: "center", borderRadius: 4 }}>
              <Typography color="text.secondary">
                No appointments yet
              </Typography>
              <Button
                variant="contained"
                sx={{ mt: 3 }}
                onClick={() => navigate("/")}
              >
                Book New Appointment
              </Button>
            </Card>
          ) : (
            appointments.map((appt) => (
              <Card
                key={appt.id}
                sx={{ mb: 2, borderRadius: 3, "&:hover": { boxShadow: 6 } }}
              >
                <CardContent>
                  <Box
                    sx={{
                      display: "flex",
                      justifyContent: "space-between",
                      alignItems: "center",
                    }}
                  >
                    <Box>
                      <Typography variant="h6" fontWeight={600}>
                        {appt.doctorName}
                      </Typography>
                      <Typography
                        color="text.secondary"
                        sx={{ display: "flex", alignItems: "center", gap: 1 }}
                      >
                        <LocalHospitalIcon fontSize="small" />{" "}
                        {appt.hospitalName}
                      </Typography>
                    </Box>

                    <Chip
                      label={appt.status}
                      color={
                        appt.status === "Scheduled" ? "success" : "default"
                      }
                      sx={{ fontWeight: 600 }}
                    />
                  </Box>

                  <Divider sx={{ my: 2 }} />

                  <Grid container spacing={3}>
                    <Grid item xs={6}>
                      <Typography variant="body2" color="text.secondary">
                        Date
                      </Typography>
                      <Typography fontWeight={500}>{appt.date}</Typography>
                    </Grid>
                    <Grid item xs={6}>
                      <Typography variant="body2" color="text.secondary">
                        Time
                      </Typography>
                      <Typography fontWeight={500}>
                        {appt.preferredTime}
                      </Typography>
                    </Grid>
                  </Grid>
                </CardContent>
              </Card>
            ))
          )}
        </Grid>
      </Grid>

      <Box sx={{ mt: 6, textAlign: "center" }}>
        <Button
          variant="contained"
          size="large"
          onClick={() => navigate("/")}
          sx={{ borderRadius: 3, px: 6, py: 1.5 }}
        >
          Browse Hospitals & Book New Appointment
        </Button>
      </Box>
    </Container>
  );
}
